import type { DataTableRowData } from '../../row-data-types.js';
/**
 * Row identification extension props.
 * @public
 */
export interface DataTableRowIdentification<TData extends DataTableRowData> {
    /**
     * Enables identification of rows independent of their index in the array.
     * @public
     */
    rowId?: (row: TData) => string;
}
/**
 * Extension interface for the Tanstack Table options.
 * @internal
 */
export interface DataTableRowIdentificationOptions {
    rowIdSeparator?: string;
}
